import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"37. Travelling And Relocation","description":"","frontmatter":{"title":"37. Travelling And Relocation","eba":"Nurses and Midwives 2024-2028","topics":["hours","shift-work","allowances","employment","redundancy"]},"headers":[],"relativePath":"ebas/nurses-midwives/allowances/37-travelling-and-relocation.md","filePath":"ebas/nurses-midwives/allowances/37-travelling-and-relocation.md"}'),s={name:"ebas/nurses-midwives/allowances/37-travelling-and-relocation.md"};function r(i,e,l,p,d,c){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_37-travelling-and-relocation" tabindex="-1">37. Travelling And Relocation <a class="header-anchor" href="#_37-travelling-and-relocation" aria-label="Permalink to &quot;37. Travelling And Relocation&quot;">​</a></h1><p>This clause concerns payment only and is not intended to exclude the requirements of <a href="/eba/ebas/nurses-midwives/consultation-disputes/11-consultation.html">clause 11</a> (Consultation) or 12 (Redundancy and Associated Entitlements) or create a new right to be directed to work at another location.</p><p><strong>37.1</strong> In this clause Base Employment Campus means a Campus of the Employer at which the Employee ordinarily starts and finishes work.</p><p><strong>37.2</strong> Where an Employee is required by the Employer to temporarily relocate from their Base Employment Campus to another Campus during a shift, the Employee will be paid the vehicle allowance at <a href="/eba/ebas/nurses-midwives/allowances/36-vehicle-allowance.html">clause 36</a>, above.</p><p>For the avoidance of doubt, the travel will occur within paid time.</p><p><strong>37.3</strong> Living away from home (applicable from 24 June 2024)</p><p><strong>(a)</strong> Where an Employee is required by their Employer to live away from their home, the Employee will be provided the following at the expense of the Employer:</p><p><strong>(i)</strong> reasonable accommodation, food and drinks; or</p><p><strong>(ii)</strong> if any of the benefits described in clause 37.3(a)(i) cannot be provided, payment of an equivalent allowance covering each benefit that is not provided. The allowance(s) will be calculated as follows:</p><p><strong>(A)</strong> at the maximum applicable rate determined by the ATO for the relevant benefit (i.e. food, drink and/or accommodation expenses) from time to time; or</p><p><strong>(B)</strong> if the amount paid by the Employee for accommodation, food or drink exceeds the ATO guideline amount and was reasonably incurred, the total cost of the accommodation, food and/or drink, subject to the Employee providing reasonable evidence to substantiate the cost(s) and their reasonableness.</p><p>Note: For vehicle allowances, see <a href="/eba/ebas/nurses-midwives/allowances/36-vehicle-allowance.html">clause 36</a>.</p><p><strong>37.4</strong> Where an Employee is required by the Employer to temporarily relocate from their Base Employment Campus to another Campus prior to a shift, the Employee will:</p><p><strong>(a)</strong> be reimbursed for additional travelling cost to the Employee (where applicable) excluding time spent travelling (which is addressed at (b) below); and</p><p><strong>(b)</strong> where travel time increases by 15 minutes or greater (to and return) be paid an allowance equal to the Employee&#39;s ordinary rate for the additional time spent when compared to the Employee&#39;s travel time to the Base Employment Campus.</p><p>Nothing in this clause 37.4 prevents an Employer requiring the travel to occur within the rostered shift.</p><p><strong>37.5</strong> Where an Employee is required by the Employer to permanently relocate from their Base Employment Campus to another Campus as a result of redundancy, the Employee will be reimbursed for additional travel costs (where applicable) in accordance with <a href="/eba/ebas/nurses-midwives/consultation-disputes/12-redundancy-and-associated-entitlements.html">clause 12.6</a> of this Agreement (Relocation).</p><p>For the avoidance of doubt, nothing in this clause limits the obligations regarding redundancy contained at <a href="/eba/ebas/nurses-midwives/consultation-disputes/12-redundancy-and-associated-entitlements.html">clause 12</a> of this Agreement.</p><p><strong>37.6</strong> Where an Employee&#39;s position is required by the Employer to permanently relocate from their Base Employment Campus to another Campus and the Employee&#39;s position is not redundant, the Employee will be reimbursed for additional travel costs (where applicable) in accordance with subclauses 12.6(b)-(f) of this Agreement.</p><p>For the avoidance of doubt, where this is a result of a Major Change, as defined in clause 11.2, the terms of <a href="/eba/ebas/nurses-midwives/consultation-disputes/11-consultation.html">clause 11</a> will apply, save that the Employer will not be required to take additional steps to mitigate or avert the cost of the relocation.</p><p><strong>37.7</strong> This clause does not apply to:</p><p><strong>(a)</strong> an Employee whose role goes across Campuses;</p><p><strong>(b)</strong> Employees who genuinely choose to work across different Campuses and it is not a requirement of the Employer, such as where an Employee elects to pick up an additional shift/s on another Campus on a permanent or ad hoc basis;</p><p><strong>(c)</strong> Casuals; or</p><p><strong>(d)</strong> in the case of clauses 37.3 and 37.6, the Stand Alone Community Health Centres specified in <a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> of this Agreement.</p><p><strong>37.8</strong> Special provisions relating to particular travel</p><p><strong>(a)</strong> Employees whose duties require them to travel will be paid first class fares and all reasonable out-of-pocket expenses.</p><p><strong>(b)</strong> Employees engaged for a distant position where a definite period of engagement is not stated will, after six months&#39; continuous service, receive a refund of first class railway, coach or plane fares and reasonable out-of-pocket expenses incurred within the State of Victoria in reaching such position.</p><p><strong>(c)</strong> Employees engaged for a distant position for a definite period will, upon completion of the term of the engagement, receive first class railway, coach or plane fares or necessary mileage for use of private car for return trip and reasonable out-of-pocket expenses incurred in travelling within the State of Victoria.</p><p>Plain language terms: travel expenses, travel reimbursement, mileage, relocation.</p>',30)])])}const u=t(s,[["render",r]]);export{h as __pageData,u as default};
